+        Hyprland.dispatch("focuswindow address:" + address);
+      } else if (runningToplevel.wayland !== null)
+        runningToplevel.wayland.activate();
+    } else if (forceNew) {
+      launchNewAppInstance(entry);
+    } else {
+      entry.execute();
+    }
+  }
