286	  function rebuildAppCatalog() {
287	    const catalog = [];
288	    const applications = DesktopEntries.applications.values;
289	    for (let index = 0; index < applications.length; ++index) {
290	      const entry = applications[index];
291	      if (entry.noDisplay || entry.name === "")
292	        continue;
293	      const keywords = entry.keywords !== undefined
294	        ? entry.keywords.join(" ") : "";
295	      const normalizedName = normalizeAppText(entry.name);
296	      catalog.push({
297	        "entry": entry,
298	        "normalizedName": normalizedName,
299	        "searchText": normalizeAppText(entry.name + " " + entry.genericName
300	          + " " + keywords + " " + entry.comment)
301	      });
302	    }
303	    catalog.sort((left, right) => left.entry.name.localeCompare(right.entry.name));
304	    appCatalog = catalog;
305	    refreshAppLauncherResults();
306	  }
