338	  function refreshAppLauncherResults() {
339	    const query = normalizeAppText(appLauncherQuery.trim());
340	    if (query === "") {
341	      appLauncherResults = appCatalog.slice();
342	    } else {
343	      const ranked = [];
344	      for (let index = 0; index < appCatalog.length; ++index) {
345	        const candidate = appCatalog[index];
346	        const score = appFuzzyScore(candidate, query);
347	        if (score >= 0)
348	          ranked.push({ "candidate": candidate, "score": score });
349	      }
350	      ranked.sort((left, right) => right.score - left.score
351	        || left.candidate.entry.name.localeCompare(right.candidate.entry.name));
352	      appLauncherResults = ranked.map(result => result.candidate);
353	    }
354	    appLauncherSelectedIndex = 0;
355	  }
