372	  function appIdentityAliases(value) {
373	    const identity = normalizeAppIdentity(value);
374	    if (identity === "")
375	      return [];
376	    const aliases = [identity];
377	    let match = identity.match(/^chrome-([a-z]+)-default$/);
378	    if (match !== null)
379	      aliases.push("crx_" + match[1]);
380	    match = identity.match(/^crx_([a-z]+)$/);
381	    if (match !== null)
382	      aliases.push("chrome-" + match[1] + "-default");
383	    return aliases;
384	  }
