386	  function appToplevelFor(entry) {
387	    const appIdentities = [];
388	    [entry.id, entry.startupClass, entry.icon].forEach(value => {
389	      appIdentityAliases(value).forEach(identity => {
390	        if (!appIdentities.includes(identity))
391	          appIdentities.push(identity);
392	      });
393	    });
394	    if (appIdentities.length === 0)
395	      return null;
396	
397	    let best = null;
398	    let bestHistory = Number.MAX_SAFE_INTEGER;
399	    const toplevels = Hyprland.toplevels.values;
400	    for (let index = 0; index < toplevels.length; ++index) {
401	      const toplevel = toplevels[index];
