308	  function appFuzzyScore(candidate, query) {
309	    const name = candidate.normalizedName;
310	    const text = candidate.searchText;
311	    if (name === query)
312	      return 10000;
313	
314	    let score = name.startsWith(query) ? 1200
315	      : name.includes(query) ? 700 : 0;
316	    let previous = -1;
317	    let streak = 0;
318	    let gaps = 0;
319	
320	    for (let index = 0; index < query.length; ++index) {
321	      const position = text.indexOf(query[index], previous + 1);
322	      if (position < 0)
323	        return -1;
324	      const gap = previous < 0 ? position : position - previous - 1;
325	      gaps += gap;
326	      streak = gap === 0 ? streak + 1 : 0;
327	      score += 20 + streak * 14;
328	      if (position === 0 || " -_./".includes(text[position - 1]))
329	        score += 45;
330	      previous = position;
331	    }
332	
333	    score -= gaps * 3;
334	    score -= Math.max(0, name.length - query.length) * 0.2;
335	    return score;
336	  }
